import{_ as e,o as r,c as a,ae as l}from"./chunks/framework.DAK3ioSj.js";const m=JSON.parse('{"title":"Memento-Skills","description":"","frontmatter":{},"headers":[],"relativePath":"radar/tech-memento-skills.md","filePath":"radar/tech-memento-skills.md"}'),o={name:"radar/tech-memento-skills.md"};function i(n,t,d,s,h,u){return r(),a("div",null,[...t[0]||(t[0]=[l('<h1 id="memento-skills" tabindex="-1">Memento-Skills <a class="header-anchor" href="#memento-skills" aria-label="Permalink to &quot;Memento-Skills&quot;">​</a></h1><blockquote><p><strong>分类</strong>: Skill 执行 / Skill 召回 | <strong>成熟度</strong>: 🟡 成长期 | <strong>综合评分</strong>: 0.53</p></blockquote><hr><h2 id="基本信息" tabindex="-1">基本信息 <a class="header-anchor" href="#基本信息" aria-label="Permalink to &quot;基本信息&quot;">​</a></h2><p><strong>一句话描述</strong>: 让 Agent 拥有&quot;长期记忆&quot; —— <strong>Read → Execute → Reflect → Write 闭环</strong> + 行为可训练 Skill Router。GAIA +26.2%、HLE +116.2%。</p><p><strong>来源</strong>:</p><ul><li>学术研究</li></ul><p><strong>链接</strong>:</p><ul><li>论文：<a href="https://arxiv.org/abs/2603.18743" target="_blank" rel="noreferrer">arXiv 2603.18743</a></li><li>GitHub：<a href="https://github.com/Memento-Teams/Memento-Skills" target="_blank" rel="noreferrer">Memento-Teams/Memento-Skills</a></li></ul><hr><h2 id="核心技术" tabindex="-1">核心技术 <a class="header-anchor" href="#核心技术" aria-label="Permalink to &quot;核心技术&quot;">​</a></h2><h3 id="read-→-execute-→-reflect-→-write-闭环" tabindex="-1">Read → Execute → Reflect → Write 闭环 <a class="header-anchor" href="#read-→-execute-→-reflect-→-write-闭环" aria-label="Permalink to &quot;Read → Execute → Reflect → Write 闭环&quot;">​</a></h3><table tabindex="0"><thead><tr><th>阶段</th><th>行为</th></tr></thead><tbody><tr><td><strong>Read</strong></td><td>从 Skill 库检索相关经验</td></tr><tr><td><strong>Execute</strong></td><td>执行任务</td></tr><tr><td><strong>Reflect</strong></td><td>反思&quot;这次做得好不好，可以改进什么&quot;</td></tr><tr><td><strong>Write</strong></td><td>将反思结果更新回 Skill 库</td></tr></tbody></table><blockquote><p>像一个会写工作日志的员工 —— 每天下班前总结经验，第二天先翻日志再开始工作。</p></blockquote><h3 id="行为可训练-skill-router" tabindex="-1">行为可训练 Skill Router <a class="header-anchor" href="#行为可训练-skill-router" aria-label="Permalink to &quot;行为可训练 Skill Router&quot;">​</a></h3><p>不只是关键词匹配，而是<strong>根据当前上下文状态学习&quot;什么情况下应该用什么 Skill&quot;</strong>。</p><h3 id="关键数字" tabindex="-1">关键数字 <a class="header-anchor" href="#关键数字" aria-label="Permalink to &quot;关键数字&quot;">​</a></h3><ul><li><strong>GAIA 基准 +26.2%</strong></li><li><strong>HLE 基准 +116.2%</strong></li></ul><hr><h2 id="技术细节" tabindex="-1">技术细节 <a class="header-anchor" href="#技术细节" aria-label="Permalink to &quot;技术细节&quot;">​</a></h2><h3 id="主要能力" tabindex="-1">主要能力 <a class="header-anchor" href="#主要能力" aria-label="Permalink to &quot;主要能力&quot;">​</a></h3><ul><li>长期记忆持久化</li><li>反思驱动 Skill 自更新</li><li>上下文敏感的 Skill 路由</li></ul><h3 id="局限性" tabindex="-1">局限性 <a class="header-anchor" href="#局限性" aria-label="Permalink to &quot;局限性&quot;">​</a></h3><ul><li>学术研究导向，产品化和易用性不如 OpenSpace、Hermes 等工程项目</li><li>反思质量依赖 LLM 自身判断</li></ul><hr><h2 id="成熟度评分" tabindex="-1">成熟度评分 <a class="header-anchor" href="#成熟度评分" aria-label="Permalink to &quot;成熟度评分&quot;">​</a></h2><table tabindex="0"><thead><tr><th>维度</th><th>评分</th><th>说明</th></tr></thead><tbody><tr><td>技术成熟度</td><td>0.55</td><td>论文 + 开源</td></tr><tr><td>创新性</td><td>0.75</td><td>闭环设计 + 行为可训练 Router 是新颖组合</td></tr><tr><td>落地程度</td><td>0.35</td><td>学术</td></tr><tr><td>生态活跃度</td><td>0.45</td><td>仓库较活跃</td></tr></tbody></table><p><strong>综合评分</strong>: <strong>0.53</strong></p><hr><h2 id="参考资料" tabindex="-1">参考资料 <a class="header-anchor" href="#参考资料" aria-label="Permalink to &quot;参考资料&quot;">​</a></h2><ul><li><a href="https://arxiv.org/abs/2603.18743" target="_blank" rel="noreferrer">Memento-Skills 论文</a></li><li><a href="https://github.com/Memento-Teams/Memento-Skills" target="_blank" rel="noreferrer">GitHub</a></li></ul>',31)])])}const b=e(o,[["render",i]]);export{m as __pageData,b as default};
